{\pard \ql \f0 \sa180 \li0 \fi0 Run this to reset the Grid Nudge Panel position back to default.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
